def _fallback_games():
    return [
        {"owner":"Jakob Marsee","game":"Miami Marlins vs Toronto Blue Jays","bucket":"CORE 1 · CLEAN LANE","role":"Event Owner","pitcher":"Braydon Fisher","time":"7:07 PM ET","archetype":"Clean lane finisher","weakness":"Elevated fastball / pull-air lane","gates":"Core gates passed"},
        {"owner":"James Wood","game":"Washington Nationals vs Cleveland Guardians","bucket":"CORE 2 · ADJACENT / TRANSFER","role":"Adjacent / Decoy Transfer Owner","pitcher":"Joey Cantillo","time":"6:10 PM ET","archetype":"Adjacent transfer bat","weakness":"Mistake pitch / transfer lane","gates":"Alt transfer gates passed"},
        {"owner":"Julio Rodriguez","game":"Seattle Mariners vs Athletics","bucket":"CORE 3 · WHO / CHAOS","role":"WHO / Chaos Owner","pitcher":"Luis Severino","time":"9:40 PM ET","archetype":"Chaos finisher","weakness":"Volatile flow / bullpen lane","gates":"Chaos gates passed"},
    ]

def _extract_games(results):
    if isinstance(results, dict):
        if isinstance(results.get('games'), list) and results['games']:
            return results['games']
        out=[]
        for key in ['core','core3','alt','alt3','chaos','chaos3','owners']:
            rows=results.get(key)
            if isinstance(rows, list):
                for r in rows:
                    if isinstance(r, dict):
                        out.append({
                            'owner': r.get('owner') or r.get('player') or 'Pending Owner',
                            'game': r.get('game') or r.get('game_key') or r.get('label') or f'Game {len(out)+1}',
                            'bucket': r.get('bucket') or r.get('core_slot') or f'GAME {len(out)+1}',
                            'role': r.get('role') or r.get('core_display_role') or r.get('archetype') or 'Owner',
                            'pitcher': r.get('pitcher') or 'Pending',
                            'time': r.get('time') or r.get('game_time_et') or '',
                            'archetype': r.get('archetype') or 'Pending',
                            'weakness': r.get('weakness') or r.get('final_reason') or 'Pending',
                            'gates': r.get('gates') or 'Hidden public view',
                        })
        if out: return out
    return _fallback_games()

def render_board(results=None):
    uploaded = st.file_uploader('START', type=['pdf','csv','xlsx','xls','txt','md'], label_visibility='collapsed', key='start_upload_overlay')
    if uploaded is not None:
        st.session_state['uploaded_file_name'] = uploaded.name
    games=_extract_games(results or {})
    payload=json.dumps(games).replace('</','<\/')
    board_src='data:image/jpeg;base64,'+REFERENCE_BOARD_B64
    html=f"""
<!doctype html><html><head><meta name='viewport' content='width=device-width,initial-scale=1'/>
<style>
*{{box-sizing:border-box}}html,body{{margin:0;background:#000;overflow:hidden;font-family:Arial,Helvetica,sans-serif;color:white}}
.viewport{{width:100vw;height:100vh;background:#000;display:flex;align-items:flex-start;justify-content:center}}
.board{{position:relative;width:min(100vw,{BOARD_W}px);aspect-ratio:{BOARD_W}/{BOARD_H};background-image:url('{{board_src}}');background-size:100% 100%;background-repeat:no-repeat;background-position:center top;overflow:hidden;}}
.hotspot{{position:absolute;cursor:pointer;z-index:20}}.hotspot:hover{{outline:2px solid rgba(255,255,255,.35);border-radius:8px}}
.cardGlow{{position:absolute;z-index:15;border-radius:10px;pointer-events:none}}.coreGlow{{box-shadow:0 0 28px 7px rgba(59,130,246,.95)}}.altGlow{{box-shadow:0 0 28px 7px rgba(239,68,68,.95)}}.chaosGlow{{box-shadow:0 0 28px 7px rgba(34,197,94,.95)}}
.liveLabel{{position:absolute;z-index:18;color:#fff;font-weight:1000;line-height:1;text-shadow:0 2px 4px rgba(0,0,0,.8);pointer-events:none}}.liveSmall{{font-size:1.05vw;color:#cbd5e1;font-weight:800;margin-top:.3vw}}
.modal{{display:none;position:absolute;left:2%;right:2%;top:13%;background:rgba(4,8,16,.97);border:1px solid rgba(255,255,255,.25);border-radius:14px;padding:18px;z-index:60;box-shadow:0 0 60px rgba(0,0,0,.9)}}.modal.show{{display:block}}.close{{position:absolute;right:14px;top:8px;font-size:26px;cursor:pointer}}
.modal h2{{margin:0 0 8px;font-size:34px;line-height:1}}.modalGame{{font-size:16px;font-weight:900;color:#cbd5e1;margin-bottom:12px}}.grid{{display:grid;grid-template-columns:repeat(4,1fr);gap:10px}}.info{{background:#0b1220;border:1px solid rgba(255,255,255,.12);border-radius:10px;padding:11px;font-size:12px;line-height:1.3}}.info b{{display:block;color:#b7ff32;font-size:14px;margin-bottom:4px}}
@media(max-width:760px){{.board{{width:100vw}}.modal{{top:8%;padding:12px}}.modal h2{{font-size:24px}}.modalGame{{font-size:12px}}.grid{{grid-template-columns:1fr 1fr;gap:6px}}.info{{font-size:9px;padding:8px}}.info b{{font-size:10px}}.liveLabel{{font-size:1.8vw}}.liveSmall{{font-size:1.15vw}}}}
</style></head><body><div class='viewport'><div class='board'>
<div class='hotspot' onclick='selectGame(0)' style='left:1.2%;top:13.4%;width:12.2%;height:12.6%;'></div><div id='gateZones'></div>
<div class='cardGlow coreGlow' style='left:1.2%;bottom:6.0%;width:31.5%;height:16.2%;'></div><div class='cardGlow altGlow' style='left:34.3%;bottom:6.0%;width:31.5%;height:16.2%;'></div><div class='cardGlow chaosGlow' style='left:67.4%;bottom:6.0%;width:31.5%;height:16.2%;'></div>
<div id='card0Text' class='liveLabel' style='left:3.2%;bottom:12.4%;font-size:2vw;'></div><div id='card0Sub' class='liveLabel liveSmall' style='left:3.2%;bottom:9.4%;'></div>
<div id='card1Text' class='liveLabel' style='left:36.4%;bottom:12.4%;font-size:2vw;'></div><div id='card1Sub' class='liveLabel liveSmall' style='left:36.4%;bottom:9.4%;'></div>
<div id='card2Text' class='liveLabel' style='left:69.5%;bottom:12.4%;font-size:2vw;'></div><div id='card2Sub' class='liveLabel liveSmall' style='left:69.5%;bottom:9.4%;'></div>
<div class='hotspot' onclick='selectGame(0)' style='left:1.2%;bottom:6.0%;width:31.5%;height:16.2%;'></div><div class='hotspot' onclick='selectGame(1)' style='left:34.3%;bottom:6.0%;width:31.5%;height:16.2%;'></div><div class='hotspot' onclick='selectGame(2)' style='left:67.4%;bottom:6.0%;width:31.5%;height:16.2%;'></div>
<div id='modal' class='modal'><div class='close' onclick='hideDetail()'>×</div><div id='modalInner'></div></div></div></div>
<script>
const games={{payload}};
const gateZones=[[13.1,14.5,10.1,11.2],[22.9,14.5,10.1,11.2],[32.7,14.5,10.1,11.2],[42.5,14.5,10.1,11.2],[52.3,14.5,10.1,11.2],[62.1,14.5,10.1,11.2],[72.0,21.5,9.8,10.7],[80.2,29.0,9.6,10.5],[72.8,41.8,9.6,10.5],[63.6,47.8,9.6,10.5],[53.5,34.4,9.6,10.5],[43.4,34.4,9.6,10.5],[33.3,34.4,9.6,10.5],[23.2,34.4,9.6,10.5],[13.1,34.4,9.6,10.5],[5.8,43.0,9.4,10.2],[4.8,55.3,9.4,10.2],[14.0,60.8,9.4,10.2],[23.7,60.8,9.4,10.2],[33.4,60.8,9.4,10.2],[43.1,60.8,9.4,10.2],[52.8,60.8,9.4,10.2],[62.5,60.8,9.4,10.2]];
function short(s,n){{s=s||'';return s.length>n?s.slice(0,n-1)+'…':s}}
function makeZones(){{const root=document.getElementById('gateZones');gateZones.forEach((z,i)=>{{const div=document.createElement('div');div.className='hotspot';div.style.left=z[0]+'%';div.style.top=z[1]+'%';div.style.width=z[2]+'%';div.style.height=z[3]+'%';div.onclick=()=>selectGame(i%games.length);root.appendChild(div);}});}}
function fillCards(){{const c=games[0]||{{}},a=games[1]||c,w=games[2]||c;document.getElementById('card0Text').textContent=short(c.owner||'Pending',22);document.getElementById('card0Sub').textContent=short((c.bucket||'CORE')+' · '+(c.game||''),50);document.getElementById('card1Text').textContent=short(a.owner||'Pending',22);document.getElementById('card1Sub').textContent=short((a.bucket||'ALT')+' · '+(a.game||''),50);document.getElementById('card2Text').textContent=short(w.owner||'Pending',22);document.getElementById('card2Sub').textContent=short((w.bucket||'CHAOS')+' · '+(w.game||''),50);}}
function selectGame(i){{const g=games[i]||games[0]||{{}};document.getElementById('modalInner').innerHTML=`<h2>${{g.owner||'Pending Owner'}}</h2><div class='modalGame'>${{g.game||''}} ${{g.time?'· '+g.time:''}}</div><div class='grid'><div class='info'><b>Archetype</b>${{g.archetype||'Pending'}}</div><div class='info'><b>Gates Passed</b>${{g.gates||'Hidden public view'}}</div><div class='info'><b>Pitcher Weakness</b>${{g.weakness||'Pending'}}</div><div class='info'><b>Lane Type</b>${{g.role||g.bucket||'Pending'}}</div></div>`;document.getElementById('modal').classList.add('show');}}
function hideDetail(){{document.getElementById('modal').classList.remove('show')}}makeZones();fillCards();
</script></body></html>
"""
    components.html(html, height=720, scrolling=False)
